{
  "compilerOptions": {
    "experimentalDecorators": true,
    "emitDecoratorMetadata": true
  }
}

// Sadə xüsusiyyət dekoratoru
function logProperty(target: any, propertyKey: string) {
  let value = target[propertyKey];

  const getter = () => {
    console.log(`Getting value of ${propertyKey}: ${value}`);
    return value;
  };

  const setter = (newValue: any) => {
    console.log(`Setting ${propertyKey} to ${newValue}`);
    value = newValue;
  };

  Object.defineProperty(target, propertyKey, {
    get: getter,
    set: setter,
    enumerable: true,
    configurable: true
  });
}

class Person {
  @logProperty
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
console.log(person.name); // Getting value of name: Alice
person.name = 'Bob'; // Setting name to Bob
console.log(person.name); // Getting value of name: Bob

// Dekorator fabriki
function logWithPrefix(prefix: string) {
  return function (target: any, propertyKey: string) {
    let value = target[propertyKey];

    const getter = () => {
      console.log(`${prefix}: Getting ${propertyKey}: ${value}`);
      return value;
    };

    const setter = (newValue: any) => {
      console.log(`${prefix}: Setting ${propertyKey} to ${newValue}`);
      value = newValue;
    };

    Object.defineProperty(target, propertyKey, {
      get: getter,
      set: setter,
      enumerable: true,
      configurable: true
    });
  };
}

class Person {
  @logWithPrefix('INFO')
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
console.log(person.name); // INFO: Getting name: Alice
person.name = 'Bob'; // INFO: Setting name to Bob
console.log(person.name); // INFO: Getting name: Bob

// TypeScript xüsusiyyət dekoratoru
function readonlyProperty(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, {
    writable: false,
    enumerable: true,
    configurable: true
  });
}

class Person {
  @readonlyProperty
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
console.log(person.name); // Alice
// person.name = 'Bob'; // Xəta: Cannot assign to read-only property

// Tip təhlükəsizliyi ilə xüsusiyyət dekoratoru
function validateString(target: any, propertyKey: string) {
  let value: string;

  const getter = () => value;
  const setter = (newValue: string) => {
    if (typeof newValue !== 'string') {
      throw new Error(`${propertyKey} must be a string`);
    }
    value = newValue;
  };

  Object.defineProperty(target, propertyKey, {
    get: getter,
    set: setter,
    enumerable: true,
    configurable: true
  });
}

class Person {
  @validateString
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
console.log(person.name); // Alice
// person.name = 123; // Xəta: name must be a string
person.name = 'Bob';
console.log(person.name); // Bob

// Səhvə yol açan xüsusiyyət dekoratoru
function restrictAccess(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, {
    get: () => {
      throw new Error(`Access to ${propertyKey} is restricted`);
    },
    set: () => {
      throw new Error(`Setting ${propertyKey} is restricted`);
    },
    enumerable: true,
    configurable: true
  });
}

class Person {
  @restrictAccess
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
// console.log(person.name); // Xəta: Access to name is restricted
// person.name = 'Bob'; // Xəta: Setting name is restricted

// Real layihə ssenarisi
function trackChanges(target: any, propertyKey: string) {
  let value: any;

  const getter = () => value;
  const setter = (newValue: any) => {
    console.log(`Property ${propertyKey} changed from ${value} to ${newValue}`);
    value = newValue;
  };

  Object.defineProperty(target, propertyKey, {
    get: getter,
    set: setter,
    enumerable: true,
    configurable: true
  });
}

class User {
  @trackChanges
  username: string;

  constructor(username: string) {
    this.username = username;
  }
}

const user = new User('Alice');
console.log(user.username); // Alice
user.username = 'Bob'; // Property username changed from Alice to Bob
console.log(user.username); // Bob

